INSERT INTO vagas (empresa_id, titulo, cargo, area, descricao, requisitos, beneficios, tipo_contrato, tipo_vaga, nivel, experiencia, carga_horaria, salario_min, salario_max) VALUES
(@empresa1, 'Analista de Suporte Júnior', 'Analista de Suporte', 'TI', 'Estamos em busca de um Analista de Suporte para auxiliar nossos clientes internos e externos.\nResponsável por manutenção de hardware, software e suporte em redes locais.\nTrabalho em equipe dinâmica e ambiente inovador.', '- Ensino Superior em TI (cursando ou completo)\n- Conhecimento básico em redes\n- Pacote Office avançado\n- Boa comunicação interpessoal', '- Plano de Saúde\n- Vale Refeição\n- Seguro de Vida', 'CLT', 'PRESENCIAL', 'Júnior', '6_MESES_A_1_ANO', '44h semanais', 2200.00, 2800.00),
(@empresa1, 'Desenvolvedor Full Stack PHP', 'Desenvolvedor', 'TI', 'Buscamos desenvolvedor proativo para atuar em projetos de e-commerce e sistemas internos.\nFoco em PHP moderno, MySQL e frameworks JavaScript (Vue ou React).\nParticipação em todas as etapas do ciclo de desenvolvimento.', '- PHP 8+\n- MySQL / PostgreSQL\n- HTML/CSS/JS\n- Git / GitHub', '- Home Office (Híbrido)\n- Bônus por Metas\n- Cursos de Especialização', 'CLT', 'HIBRIDO', 'Pleno', '1_A_3_ANOS', '40h semanais', 4500.00, 6500.00),
(@empresa1, 'Auxiliar Administrativo', 'Auxiliar Administrativo', 'Administração', 'Atendimento telefônico, organização de documentos e auxílio no faturamento.\nUso constante de planilhas de controle e sistema ERP da empresa.\nOrganização de reuniões e suporte à diretoria.', '- Ensino Médio completo\n- Conhecimento em Excel\n- Boa escrita\n- Organização extrema', '- Vale Transporte\n- Cesta Básica\n- Convênio Farmácia', 'CLT', 'PRESENCIAL', 'Júnior', 'SEM_EXPERIENCIA', '44h semanais', 1600.00, 1900.00),
(@empresa1, 'Técnico de Infraestrutura', 'Técnico de TI', 'TI', 'Manutenção de servidores e cabeamento estruturado.\nInstalação de câmeras e sistemas de segurança digital.\nSuporte avançado a sistemas operacionais Windows e Linux.', '- Formação Técnica em TI\n- Experiência com Mikrotik\n- CNH B\n- Disponibilidade para viagens curtas', '- Veículo da empresa\n- Diárias de Viagem\n- Seguro de Vida', 'CLT', 'PRESENCIAL', 'Pleno', '1_A_3_ANOS', '44h semanais', 2800.00, 3500.00),
(@empresa1, 'Secretária Executiva', 'Secretária', 'Administração', 'Gestão de agenda da diretoria, recepção de clientes e organização de eventos corporativos.\nRedação de ofícios e atas de reuniões.\nControle de viagens e estadias.', '- Inglês intermediário\n- Experiência anterior na função\n- Ensino Superior completo ou cursando\n- Discrição e profissionalismo', '- Plano Odontológico\n- PLR Semestral\n- Refeitório no local', 'CLT', 'PRESENCIAL', 'Sênior', 'MAIS_DE_3_ANOS', '44h semanais', 3000.00, 4200.00),
(@empresa1, 'Analista Financeiro', 'Analista Financeiro', 'Administração', 'Conciliação bancária, contas a pagar e receber e emissão de notas fiscais.\nAuxílio no fechamento contábil e gestão de fluxo de caixa.\nRelacionamento com bancos e fornecedores.', '- Formação em Administração ou Contábeis\n- Excel Avançado\n- Experiência com ERP\n- Perfil analítico', '- Plano de Saúde\n- Vale Alimentação\n- Auxílio Educação', 'CLT', 'PRESENCIAL', 'Pleno', '1_A_3_ANOS', '44h semanais', 3500.00, 4800.00),
(@empresa1, 'Web Designer', 'Designer', 'Design', 'Criação de interfaces para sites e landing pages.\nDesenvolvimento de banners para redes sociais e peças de marketing digital.\nManutenção visual de sistemas internos.', '- Domínio de Figma ou Adobe XD\n- Photoshop e Illustrator\n- Noções de UX/UI\n- Portfólio atualizado', '- Bônus por performance\n- Horário flexível\n- Day off no aniversário', 'CLT', 'REMOTO', 'Pleno', '1_A_3_ANOS', '40h semanais', 3200.00, 4500.00),
(@empresa1, 'Estagiário de Programação', 'Estagiário', 'TI', 'Auxílio na correção de bugs e implementação de pequenas features.\nAprendizado prático em ambiente profissional com mentoria de seniores.\nFoco em desenvolvimento web moderno.', '- Cursando TI (noturno)\n- Lógica de programação sólida\n- Vontade de aprender\n- Proatividade', '- Bolsa Auxílio\n- Seguro de Vida\n- Possibilidade de Efetivação', 'Estágio', 'HIBRIDO', 'Sem experiência', 'SEM_EXPERIENCIA', '30h semanais', 1000.00, 1200.00),
(@empresa1, 'Gerente de TI', 'Gerente', 'TI', 'Gestão de equipe de desenvolvimento e suporte.\nPlanejamento estratégico de infraestrutura e segurança da informação.\nGestão de contratos com fornecedores de tecnologia.', '- Pós-graduação na área\n- Experiência em liderança de equipes\n- Inglês Avançado\n- Visão de negócio', '- Carro da empresa\n- Notebook e Celular\n- Bônus agressivo por KPIs', 'CLT', 'PRESENCIAL', 'Gestão', 'MAIS_DE_3_ANOS', '44h semanais', 8000.00, 12000.00),
(@empresa1, 'Analista de Dados (BI)', 'Analista de BI', 'TI', 'Criação de dashboards e relatórios para tomada de decisão estratégica.\nExtração e tratamento de dados de diversas fontes.\nIdentificação de padrões e insights de negócio.', '- SQL Avançado\n- Power BI ou Tableau\n- Conhecimento em Estatística\n- Python para análise de dados', '- Participação nos Lucros\n- Auxílio Inglês\n- Academia (Gympass)', 'PJ', 'REMOTO', 'Sênior', 'MAIS_DE_3_ANOS', '40h semanais', 6000.00, 9000.00);
