(@empresa2, 'Vendedor de Loja', 'Vendedor', 'Comércio', 'Atendimento ao público em loja de decoração e presentes.\nOrganização de vitrines e controle de estoque do setor.\nFechamento de vendas e cadastro de clientes no sistema.', '- Ensino Médio completo\n- Disponibilidade de horário (incluindo sábados)\n- Simpatia e boa dicção\n- Gosto por vendas', '- Comissão sobre vendas\n- Vale Transporte\n- Treinamentos constantes', 'CLT', 'PRESENCIAL', 'Júnior', 'SEM_EXPERIENCIA', '44h semanais', 1500.00, 2500.00),
(@empresa2, 'Motorista Entregador (Cat C/D)', 'Motorista', 'Logística', 'Entregas de mercadorias em Porto Ferreira e região.\nConferência de notas fiscais e carga/descarga eventual.\nZelar pela manutenção básica do veículo da empresa.', '- CNH C ou D válida\n- Experiência com caminhão\n- Conhecimento da região\n- Responsabilidade no trânsito', '- Vale Refeição\n- Diárias de viagem\n- Seguro de Vida', 'CLT', 'PRESENCIAL', 'Pleno', '1_A_3_ANOS', '44h semanais', 2500.00, 3200.00),
(@empresa2, 'Operador de Caixa', 'Caixa', 'Comércio', 'Operação de caixa em supermercado de grande porte.\nRecebimento de valores, abertura e fechamento de caixa.\nAtendimento cordial ao cliente e oferta de produtos promocionais.', '- Ensino Médio completo\n- Agilidade numérica\n- Experiência anterior será diferencial\n- Residir em Porto Ferreira', '- Quebra de Caixa\n- Vale Transporte\n- Auxílio Creche', 'CLT', 'PRESENCIAL', 'Júnior', 'SEM_EXPERIENCIA', '44h semanais', 1600.00, 1850.00),
(@empresa2, 'Estoquista / Conferente', 'Estoquista', 'Logística', 'Recebimento de mercadorias, conferência com nota fiscal e organização de prateleiras.\nSeparação de pedidos para expedição.\nControle de inventário cíclico.', '- Ensino Médio\n- Proatividade e força física\n- Noções de informática\n- Atenção a detalhes', '- Cesta Básica\n- Vale Refeição\n- Convênio Médico', 'CLT', 'PRESENCIAL', 'Júnior', '6_MESES_A_1_ANO', '44h semanais', 1700.00, 2000.00),
(@empresa2, 'Auxiliar de Limpeza', 'Auxiliar de Limpeza', 'Serviços Gerais', 'Limpeza e conservação de ambientes de escritório e áreas comuns.\nControle de estoque de materiais de limpeza.\nZelar pela higiene e organização das dependências.', '- Alfabetizado\n- Experiência na função\n- Residir em Porto Ferreira\n- Disposição para trabalho físico', '- Vale Transporte\n- Uniforme completo\n- Cesta Básica', 'CLT', 'PRESENCIAL', 'Júnior', 'SEM_EXPERIENCIA', '44h semanais', 1450.00, 1600.00),
(@empresa2, 'Recepcionista de Consultório', 'Recepcionista', 'Saúde', 'Agendamento de consultas, atendimento telefônico e recepção de pacientes.\nOrganização de prontuários e autorização de guias de convênio.\nLimpeza da área de espera.', '- Ensino Médio completo\n- Informática básica\n- Cordialidade e paciência\n- Organização', '- Vale Transporte\n- Convênio Médico\n- Insalubridade (se aplicável)', 'CLT', 'PRESENCIAL', 'Júnior', 'SEM_EXPERIENCIA', '44h semanais', 1650.00, 1900.00),
(@empresa2, 'Fisioterapeuta', 'Fisioterapeuta', 'Saúde', 'Atendimento clínico em clínica de reabilitação física.\nRealização de avaliações e planos de tratamento.\nOrientação de pacientes em exercícios terapêuticos.', '- Graduação completa em Fisioterapia\n- Registro ativo no CREFITO\n- Desejável especialização em Ortopedia\n- Pontualidade', '- Honorários por atendimento\n- Ambiente climatizado\n- Equipamentos modernos', 'PJ', 'PRESENCIAL', 'Pleno', '1_A_3_ANOS', '30h semanais', 3000.00, 5000.00),
(@empresa2, 'Cozinheiro(a)', 'Cozinheiro', 'Comércio', 'Preparação de pratos à la carte e self-service em restaurante central.\nGestão da equipe de auxiliares e controle de estoque de insumos.\nGarantir as normas de vigilância sanitária.', '- Experiência comprovada como cozinheiro\n- Curso de Manipulação de Alimentos\n- Liderança de equipe\n- Criatividade culinária', '- Refeição no local\n- Caixinha (Gorjetas)\n- Vale Transporte', 'CLT', 'PRESENCIAL', 'Sênior', 'MAIS_DE_3_ANOS', '44h semanais', 2200.00, 3500.00),
(@empresa2, 'Analista de RH (Recrutamento)', 'Analista de RH', 'RH', 'Triagem de currículos, realização de entrevistas e integração de novos colaboradores.\nApoio nas rotinas de departamento pessoal e clima organizacional.\nDivulgação de vagas em canais estratégicos.', '- Formação em Psicologia ou RH\n- Experiência em R&S\n- Noções de leis trabalhistas\n- Boa oratória', '- Auxílio Educação\n- Plano de Saúde\n- Vale Alimentação', 'CLT', 'PRESENCIAL', 'Pleno', '1_A_3_ANOS', '44h semanais', 2800.00, 3800.00),
(@empresa2, 'Gerente de Loja', 'Gerente', 'Comércio', 'Gestão completa de unidade de varejo, incluindo equipe, estoque e metas de vendas.\nTreinamento de funcionários e gestão de conflitos.\nRelatórios de performance para a diretoria.', '- Experiência em gestão de varejo\n- Foco em resultados\n- Ensino Superior desejável\n- Disponibilidade de horário', '- Participação nos lucros\n- Veículo para uso profissional\n- Convênio Odontológico', 'CLT', 'PRESENCIAL', 'Gestão', 'MAIS_DE_3_ANOS', '44h semanais', 4500.00, 7000.00);
INSERT INTO vagas (empresa_id, titulo, cargo, area, descricao, requisitos, beneficios, tipo_contrato, tipo_vaga, nivel, experiencia, carga_horaria, salario_min, salario_max) VALUES
(@empresa3, 'Operador de Forno Cerâmico', 'Operador de Forno', 'Produção', 'Operação de fornos contínuos em indústria de cerâmica artística.\nControle de temperatura e ciclo de queima das peças.\nInspeção visual das peças após a queima.', '- Experiência em cerâmica\n- Disponibilidade para turnos (revezamento)\n- Residir em Porto Ferreira\n- Atenção técnica', '- Adicional Noturno\n- Cesta Básica Robustecida\n- Plano de Saúde', 'CLT', 'PRESENCIAL', 'Pleno', '1_A_3_ANOS', '44h semanais', 2000.00, 2600.00),
(@empresa3, 'Auxiliar de Produção (Geral)', 'Auxiliar de Produção', 'Produção', 'Atuar em diversas etapas da linha de produção: moldagem, acabamento e embalagem.\nTransporte interno de materiais e organização do setor de trabalho.\nCarga e descarga de caminhões.', '- Disposição física\n- Ensino Fundamental completo\n- Pontualidade britânica\n- Vontade de crescer na indústria', '- Refeitório no local\n- Vale Transporte\n- Prêmio Assiduidade', 'CLT', 'PRESENCIAL', 'Júnior', 'SEM_EXPERIENCIA', '44h semanais', 1550.00, 1800.00),
(@empresa3, 'Pintor Artístico (Cerâmica)', 'Pintor', 'Produção', 'Pintura manual de peças de cerâmica conforme modelos pré-definidos.\nUso de tintas e esmaltes específicos para alta temperatura.\nAcabamento detalhado e artístico das peças.', '- Habilidade manual e artística\n- Experiência com pintura manual\n- Paciência e detalhismo\n- Teste prático no local', '- Ambiente criativo\n- Bônus por produtividade\n- Convênio Farmácia', 'CLT', 'PRESENCIAL', 'Pleno', '1_A_3_ANOS', '44h semanais', 1800.00, 2500.00),
(@empresa3, 'Eletricista de Manutenção', 'Eletricista', 'Produção', 'Manutenção corretiva e preventiva de máquinas industriais e motores.\nInstalações elétricas em baixa e média tensão.\nLeitura e interpretação de esquemas elétricos.', '- Curso Técnico em Elétrica ou Eletromecânica\n- NR10 válida\n- Experiência em indústria\n- Proatividade', '- Periculosidade (30%)\n- Plano de Saúde\n- Vale Alimentação', 'CLT', 'PRESENCIAL', 'Pleno', '1_A_3_ANOS', '44h semanais', 2800.00, 4000.00),
(@empresa3, 'Mecânico Industrial', 'Mecânico', 'Produção', 'Manutenção de prensas, compressores e sistemas pneumáticos.\nLubrificação de máquinas e troca de rolamentos/correias.\nSolda básica e pequenos reparos em estruturas.', '- Curso de Mecânica Industrial (SENAI)\n- Experiência em manutenção de fábrica\n- Conhecimento em pneumática\n- CNH B', '- Vale Refeição\n- Seguro de Vida\n- Auxílio Ferramentas', 'CLT', 'PRESENCIAL', 'Pleno', '1_A_3_ANOS', '44h semanais', 2700.00, 3800.00),
(@empresa3, 'Líder de Expedição', 'Líder', 'Logística', 'Coordenação da equipe de carregamento e conferência de pedidos.\nEmissão de romaneios e notas fiscais de saída.\nGestão de estoque de produtos acabados.', '- Experiência em logística industrial\n- Liderança de equipes\n- Domínio de sistemas ERP\n- Organização', '- Adicional de Cargo de Confiança\n- PLR Anual\n- Convênio Odontológico', 'CLT', 'PRESENCIAL', 'Sênior', 'MAIS_DE_3_ANOS', '44h semanais', 3200.00, 4500.00),
(@empresa3, 'Analista de Qualidade', 'Analista de Qualidade', 'Produção', 'Inspeção de matéria-prima e produtos acabados conforme normas.\nImplantação de melhorias nos processos produtivos.\nTreinamento de funcionários em boas práticas de fabricação.', '- Ensino Superior em Engenharia ou Gestão da Produção\n- Conhecimento em ferramentas da qualidade\n- Experiência em indústria cerâmica será diferencial\n- Perfil rigoroso', '- Vale Alimentação\n- Plano de Saúde\n- Auxílio Creche', 'CLT', 'PRESENCIAL', 'Pleno', '1_A_3_ANOS', '44h semanais', 3000.00, 4200.00),
(@empresa3, 'Torneiro Mecânico', 'Torneiro', 'Produção', 'Uso de torno convencional para fabricação de peças de reposição industrial.\nLeitura de desenhos técnicos e uso de instrumentos de medição.\nZelar pelas ferramentas e máquinas da oficina.', '- Curso de Torneiro Mecânico\n- Experiência comprovada\n- Precisão técnica\n- Disponibilidade imediata', '- Insalubridade\n- Cesta Básica\n- Café da manhã na empresa', 'CLT', 'PRESENCIAL', 'Sênior', 'MAIS_DE_3_ANOS', '44h semanais', 2800.00, 3900.00),
(@empresa3, 'Assistente de PCP', 'Assistente', 'Produção', 'Auxílio no Planejamento e Controle da Produção.\nLançamento de ordens de produção e controle de prazos.\nAcompanhamento do fluxo de materiais entre setores.', '- Estudante de Engenharia ou Administração\n- Excel intermediário\n- Boa comunicação\n- Senso de urgência', '- Bolsa Auxílio competitiva\n- Possibilidade de crescimento\n- Seguro de Vida', 'CLT', 'PRESENCIAL', 'Júnior', '6_MESES_A_1_ANO', '44h semanais', 1800.00, 2300.00),
(@empresa3, 'Encarregado de Produção', 'Encarregado', 'Produção', 'Gestão direta da linha de produção, garantindo metas e segurança.\nGestão de pessoal (escalas, faltas, treinamentos).\nApoio à gerência industrial em melhorias.', '- Vasta experiência em chão de fábrica\n- Habilidade em gestão de pessoas\n- Resolução de conflitos\n- Visão sistêmica', '- PLR\n- Veículo da empresa\n- Plano de Saúde Top', 'CLT', 'PRESENCIAL', 'Gestão', 'MAIS_DE_3_ANOS', '44h semanais', 4500.00, 6500.00);
